fn is_inf(x: f32) -> bool {
    let bits: u32 = bitcast<u32>(x);
    let exp  = (bits >> 23u) & 0xffu;
    let mant = bits & 0x7fffffu;
    return exp == 0xffu && mant == 0u;
}

